#include <stdio.h>
#include <string.h>

unsigned X;
void srand1(unsigned S){
    X = S;
}
unsigned nextInteger1(void){
    X = X * 1103515245 + 12345;
    return (X / 65536) % 32768;
}
void generator1(int N, unsigned S, int A[]){
    srand1(S);
    for(int i=1;i<=N;i++){
        A[i] = nextInteger1() % 2;
    }
}

unsigned x, y, z, w;
void srand2(unsigned S){
    x = S;
    y = x * S;
    z = y * S;
    w = z * S;
}
unsigned nextInteger2(void){
    unsigned t = x ^ (x << 11);
    x = y; y = z; z = w;
    return w = (w ^ (w >> 19)) ^ (t ^ (t >> 8));
}
void generator2(int N, unsigned S, int A[]){
    srand2(S);
    for(int i=1;i<=N;i++){
        A[i] = nextInteger2() % 2;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while(T--) {
        char str[200001];
        scanf("%s", str);
        int N = strlen(str);
        int A[N+1];
        for(int i=1;i<=N;i++) {
            A[i] = str[i-1] - '0';
        }
        int found = 0;
        for(int S=0;S<=500;S++) {
            int B[N+1];
            generator1(N, S, B);
            int match = 1;
            for(int i=1;i<=N;i++) {
                if(A[i] != B[i]) {
                    match = 0;
                    break;
                }
            }
            if(match) {
                printf("LCG\n");
                found = 1;
                break;
            }
        }
        if(!found) {
            for(int S=0;S<=500;S++) {
                int B[N+1];
                generator2(N, S, B);
                int match = 1;
                for(int i=1;i<=N;i++) {
                    if(A[i] != B[i]) {
                        match = 0;
                        break;
                    }
                }
                if(match) {
                    printf("Xorshift\n");
                    break;
                }
            }
        }
    }
    return 0;
}

