import java.util.Scanner;
public class Main {
    static long X;
    static void srand1(long S){
        X = S;
    }
    static long nextInteger1(){
        X = X * 1103515245L + 12345;
        return (X / 65536) % 32768;
    }
    static void generator1(int N, long S, int[] A){
        srand1(S);
        for(int i=1;i<=N;i++){
            A[i] = (int)(nextInteger1() % 2);
        }
    }

    static long x, y, z, w;
    static void srand2(long S){
        x = S;
        y = x * S;
        z = y * S;
        w = z * S;
    }
    static long nextInteger2(){
        long t = x ^ (x << 11);
        x = y; y = z; z = w;
        return w = (w ^ (w >> 19)) ^ (t ^ (t >> 8));
    }
    static void generator2(int N, long S, int[] A){
        srand2(S);
        for(int i=1;i<=N;i++){
            A[i] = (int)(nextInteger2() % 2);
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while(T-- > 0) {
            String str = sc.next();
            int N = str.length();
            int[] A = new int[N+1];
            for(int i=1;i<=N;i++) {
                A[i] = str.charAt(i-1) - '0';
            }
            boolean found = false;
            for(int S=0;S<=500;S++) {
                int[] B = new int[N+1];
                generator1(N, S, B);
                boolean match = true;
                for(int i=1;i<=N;i++) {
                    if(A[i] != B[i]) {
                        match = false;
                        break;
                    }
                }
                if(match) {
                    System.out.println("LCG");
                    found = true;
                    break;
                }
            }
            if(!found) {
                for(int S=0;S<=500;S++) {
                    int[] B = new int[N+1];
                    generator2(N, S, B);
                    boolean match = true;
                    for(int i=1;i<=N;i++) {
                        if(A[i] != B[i]) {
                            match = false;
                            break;
                        }
                    }
                    if(match) {
                        System.out.println("Xorshift");
                        break;
                    }
                }
            }
        }
    }
}

